```javascript
function solve(words) {
    const n = words.length;
    if (n === 0) return [];
    if (n === 1) return [0];

    function computeLCP(a, b) {
        let minLen = Math.min(a.length, b.length);
        for (let i = 0; i < minLen; i++) {
            if (a[i] !== b[i]) {
                return i;
            }
        }
        return minLen;
    }

    const lcp = new Array(n - 1);
    for (let i = 0; i < n - 1; i++) {
        lcp[i] = computeLCP(words[i], words[i + 1]);
    }

    const prefix_max = new Array(n - 1);
    prefix_max[0] = lcp[0];
    for (let i = 1; i < n - 1; i++) {
        prefix_max[i] = Math.max(prefix_max[i - 1], lcp[i]);
    }

    const suffix_max = new Array(n - 1);
    suffix_max[n - 2] = lcp[n - 2];
    for (let i = n - 3; i >= 0; i--) {
        suffix_max[i] = Math.max(suffix_max[i + 1], lcp[i]);
    }

    const answer = new Array(n);
    for (let i = 0; i < n; i++) {
        let max_original = 0;
        if (i === 0) {
            if (n - 2 >= 1) {
                max_original = suffix_max[1];
            }
        } else if (i === n - 1) {
            if (n - 3 >= 0) {
                max_original = prefix_max[n - 3];
            }
        } else {
            let left_part = 0;
            if (i - 2 >= 0) {
                left_part = prefix_max[i - 2];
            }
            let right_part = 0;
            if (i + 1 <= n - 2) {
                right_part = suffix_max[i + 1];
            }
            max_original = Math.max(left_part, right_part);
        }

        let new_lcp = 0;
        if (i > 0 && i < n - 1) {
            new_lcp = computeLCP(words[i - 1], words[i + 1]);
        }

        answer[i] = Math.max(max_original, new_lcp);
    }

    return answer;
}
